+#[test]
+fn test_engine_transition_chain() {
+    let mut engine = ArrayFastLaneEngine::new(epoch(1));
+    engine.register_array("arr-1", ElementKind::Empty, 0);
+
+    // Empty → PackedSmi
+    let r1 = engine.transition_element_kind(
+        "arr-1",
