+// ---------------------------------------------------------------------------
+// SymmetryReason
+// ---------------------------------------------------------------------------
+
+#[test]
+fn symmetry_reason_tags_unique() {
+    let reasons = vec![
+        SymmetryReason::WithinThreshold {
+            max_distance_millionths: 1000,
