+#[test]
+fn domain_display_matches_serde() {
+    for d in ArtifactDomain::ALL {
+        let json = serde_json::to_string(d).unwrap();
+        let display = d.to_string();
+        assert_eq!(json, format!("\"{display}\""));
+    }
+}
