+        CompressionRefusalReason::EpochMismatch {
+            artifact_epoch: 1,
+            reference_epoch: 2,
+        },
+        CompressionRefusalReason::SuspiciousRatio {
+            ratio_millionths: 500,
+        },
+        CompressionRefusalReason::DomainStrategyMismatch {
